def gen(rng, size):
    count = rng.randint(1, min(max(size, 1), 10))
    parts = []
    for i in range(count):
        num = rng.randint(1, 9)
        den = rng.randint(1, 9)
        sign = rng.choice(['+', '-'])
        if i == 0 and sign == '+':
            parts.append('%d/%d' % (num, den))
        else:
            parts.append('%s%d/%d' % (sign, num, den))
    return [''.join(parts)]

