class Solution:
    def fractionAddition(self, expression):
        from fractions import Fraction
        i = 0
        n = len(expression)
        total = Fraction(0)
        while i < n:
            sign = 1
            if expression[i] == '+':
                i += 1
            elif expression[i] == '-':
                sign = -1
                i += 1
            num = 0
            while expression[i].isdigit():
                num = num * 10 + int(expression[i])
                i += 1
            i += 1
            den = 0
            while i < n and expression[i].isdigit():
                den = den * 10 + int(expression[i])
                i += 1
            total += Fraction(sign * num, den)
        return '%d/%d' % (total.numerator, total.denominator)

