var fractionAddition = function(expression) {
    const gcd = (a, b) => { a = Math.abs(a); b = Math.abs(b); while (b) { [a, b] = [b, a % b]; } return a; };
    let num = 0, den = 1;
    let i = 0;
    const n = expression.length;
    const isDigit = (ch) => ch >= '0' && ch <= '9';
    while (i < n) {
        let sign = 1;
        if (expression[i] === '+') { i++; }
        else if (expression[i] === '-') { sign = -1; i++; }
        let a = 0;
        while (isDigit(expression[i])) { a = a * 10 + (expression.charCodeAt(i) - 48); i++; }
        i++;
        let b = 0;
        while (i < n && isDigit(expression[i])) { b = b * 10 + (expression.charCodeAt(i) - 48); i++; }
        a *= sign;
        num = num * b + a * den;
        den = den * b;
        const g = gcd(num, den);
        if (g) { num = num / g; den = den / g; }
    }
    if (den < 0) { num = -num; den = -den; }
    return num + '/' + den;
};
